1вҶ’import { useEffect, useRef } from 'react'
2вҶ’import * as THREE from 'three'
3вҶ’
4вҶ’export default function HeroScene3D() {
5вҶ’  const mountRef = useRef(null)
6вҶ’
7вҶ’  useEffect(() => {
8вҶ’    const container = mountRef.current
9вҶ’    if (!container) return
10вҶ’
11вҶ’    // Respect reduced motion
12вҶ’    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches
13вҶ’    const isMobile = window.innerWidth < 768
14вҶ’
15вҶ’    // Scene setup
16вҶ’    const scene = new THREE.Scene()
17вҶ’    const W = container.clientWidth
18вҶ’    const H = container.clientHeight
19вҶ’
20вҶ’    const camera = new THREE.PerspectiveCamera(55, W / H, 0.1, 100)
21вҶ’    camera.position.z = 7
22вҶ’    camera.position.x = 1.2
23вҶ’
24вҶ’    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: !isMobile })
25вҶ’    renderer.setSize(W, H)
26вҶ’    renderer.setPixelRatio(Math.min(window.devicePixelRatio, isMobile ? 1 : 2))
27вҶ’    renderer.setClearColor(0x000000, 0)
28вҶ’    container.appendChild(renderer.domElement)
29вҶ’
30вҶ’    // Colors matching portfolio palette
31вҶ’    const C1 = new THREE.Color('#38bdf8') // sky
32вҶ’    const C2 = new THREE.Color('#a78bfa') // violet
33вҶ’    const C3 = new THREE.Color('#f472b6') // pink
34вҶ’    const C4 = new THREE.Color('#34d399') // emerald
35вҶ’
36вҶ’    // в”Җв”Җ Main TorusKnot в”Җв”Җ
37вҶ’    const torusGeo = new THREE.TorusKnotGeometry(1.0, 0.3, isMobile ? 64 : 128, isMobile ? 8 : 24)
38вҶ’    const torusMat = new THREE.MeshBasicMaterial({
39вҶ’      color: C1,
40вҶ’      wireframe: true,
41вҶ’      transparent: true,
42вҶ’      opacity: 0.1,
43вҶ’    })
44вҶ’    const torusKnot = new THREE.Mesh(torusGeo, torusMat)
45вҶ’    scene.add(torusKnot)
46вҶ’
47вҶ’    // Inner glow mesh (solid, very transparent)
48вҶ’    const glowMat = new THREE.MeshBasicMaterial({
49вҶ’      color: C2,
50вҶ’      transparent: true,
51вҶ’      opacity: 0.02,
52вҶ’      side: THREE.DoubleSide,
53вҶ’    })
54вҶ’    const glowMesh = new THREE.Mesh(torusGeo, glowMat)
55вҶ’    scene.add(glowMesh)
56вҶ’
57вҶ’    // в”Җв”Җ Orbiting Icosahedrons в”Җв”Җ
58вҶ’    const orbiters = []
59вҶ’    const orbiterCount = isMobile ? 3 : 6
60вҶ’    const orbiterColors = [C1, C2, C3, C4, C1, C3]
61вҶ’    for (let i = 0; i < orbiterCount; i++) {
62вҶ’      const size = 0.08 + Math.random() * 0.12
63вҶ’      const geo = new THREE.IcosahedronGeometry(size, 0)
64вҶ’      const mat = new THREE.MeshBasicMaterial({
65вҶ’        color: orbiterColors[i % orbiterColors.length],
66вҶ’        wireframe: true,
67вҶ’        transparent: true,
68вҶ’        opacity: 0.25,
69вҶ’      })
70вҶ’      const mesh = new THREE.Mesh(geo, mat)
71вҶ’
72вҶ’      // Orbit parameters
73вҶ’      const orbit = {
74вҶ’        mesh,
75вҶ’        radius: 2.2 + Math.random() * 1.2,
76вҶ’        speed: 0.3 + Math.random() * 0.5,
77вҶ’        phase: (Math.PI * 2 * i) / orbiterCount + Math.random() * 0.5,
78вҶ’        tilt: Math.random() * Math.PI * 0.5,
79вҶ’        rotSpeed: 0.5 + Math.random() * 1.5,
80вҶ’      }
81вҶ’      orbiters.push(orbit)
82вҶ’      scene.add(mesh)
83вҶ’    }
84вҶ’
85вҶ’    // в”Җв”Җ Floating particles в”Җв”Җ
86вҶ’    const particleCount = isMobile ? 30 : 80
87вҶ’    const particleGeo = new THREE.BufferGeometry()
88вҶ’    const particlePositions = new Float32Array(particleCount * 3)
89вҶ’    const particleSizes = new Float32Array(particleCount)
90вҶ’    for (let i = 0; i < particleCount; i++) {
91вҶ’      particlePositions[i * 3] = (Math.random() - 0.5) * 10
92вҶ’      particlePositions[i * 3 + 1] = (Math.random() - 0.5) * 10
93вҶ’      particlePositions[i * 3 + 2] = (Math.random() - 0.5) * 6
94вҶ’      particleSizes[i] = Math.random() * 3 + 1
95вҶ’    }
96вҶ’    particleGeo.setAttribute('position', new THREE.BufferAttribute(particlePositions, 3))
97вҶ’    particleGeo.setAttribute('size', new THREE.BufferAttribute(particleSizes, 1))
98вҶ’    const particleMat = new THREE.PointsMaterial({
99вҶ’      color: C1,
100вҶ’      size: 0.03,
101вҶ’      transparent: true,
102вҶ’      opacity: 0.4,
103вҶ’      sizeAttenuation: true,
104вҶ’    })
105вҶ’    const particles = new THREE.Points(particleGeo, particleMat)
106вҶ’    scene.add(particles)
107вҶ’
108вҶ’    // в”Җв”Җ Mouse tracking в”Җв”Җ
109вҶ’    const mouse = { x: 0, y: 0, targetX: 0, targetY: 0 }
110вҶ’    const onMouseMove = (e) => {
111вҶ’      mouse.targetX = (e.clientX / window.innerWidth) * 2 - 1
112вҶ’      mouse.targetY = -(e.clientY / window.innerHeight) * 2 + 1
113вҶ’    }
114вҶ’    window.addEventListener('mousemove', onMouseMove)
115вҶ’
116вҶ’    // в”Җв”Җ Animation в”Җв”Җ
117вҶ’    const clock = new THREE.Clock()
118вҶ’    let animId
119вҶ’
120вҶ’    function animate() {
121вҶ’      animId = requestAnimationFrame(animate)
122вҶ’      const t = clock.getElapsedTime()
123вҶ’      const speed = prefersReduced ? 0.15 : 1
124вҶ’
125вҶ’      // Smooth mouse interpolation
126вҶ’      mouse.x += (mouse.targetX - mouse.x) * 0.04
127вҶ’      mouse.y += (mouse.targetY - mouse.y) * 0.04
128вҶ’
129вҶ’      // Main torusKnot rotation + mouse tilt
130вҶ’      torusKnot.rotation.x = t * 0.12 * speed + mouse.y * 0.3
131вҶ’      torusKnot.rotation.y = t * 0.18 * speed + mouse.x * 0.3
132вҶ’      torusKnot.rotation.z = t * 0.06 * speed
133вҶ’
134вҶ’      // Pulse opacity
135вҶ’      torusMat.opacity = 0.08 + Math.sin(t * 0.8) * 0.04
136вҶ’      glowMat.opacity = 0.015 + Math.sin(t * 0.5) * 0.01
137вҶ’
138вҶ’      // Glow mesh follows with slight lag
139вҶ’      glowMesh.rotation.copy(torusKnot.rotation)
140вҶ’      glowMesh.rotation.x += 0.1
141вҶ’      glowMesh.rotation.y += 0.15
142вҶ’
143вҶ’      // Orbiting icosahedrons
144вҶ’      orbiters.forEach((o) => {
145вҶ’        const angle = t * o.speed * speed + o.phase
146вҶ’        o.mesh.position.x = Math.cos(angle) * o.radius
147вҶ’        o.mesh.position.y = Math.sin(angle) * o.radius * Math.cos(o.tilt)
148вҶ’        o.mesh.position.z = Math.sin(angle) * o.radius * Math.sin(o.tilt) * 0.5
149вҶ’        o.mesh.rotation.x = t * o.rotSpeed * speed
150вҶ’        o.mesh.rotation.y = t * o.rotSpeed * 0.7 * speed
151вҶ’      })
152вҶ’
153вҶ’      // Particles gentle drift
154вҶ’      const posArr = particles.geometry.attributes.position.array
155вҶ’      for (let i = 0; i < particleCount; i++) {
156вҶ’        posArr[i * 3 + 1] += Math.sin(t + i) * 0.001
157вҶ’        posArr[i * 3] += Math.cos(t * 0.5 + i * 0.3) * 0.0005
158вҶ’      }
159вҶ’      particles.geometry.attributes.position.needsUpdate = true
160вҶ’      particles.rotation.y = t * 0.02 * speed
161вҶ’
162вҶ’      // Color cycling
163вҶ’      const hue = (t * 0.05) % 1
164вҶ’      torusMat.color.setHSL(hue * 0.15 + 0.55, 0.8, 0.65)
165вҶ’
166вҶ’      renderer.render(scene, camera)
167вҶ’    }
168вҶ’    animate()
169вҶ’
170вҶ’    // в”Җв”Җ Resize в”Җв”Җ
171вҶ’    const onResize = () => {
172вҶ’      const w = container.clientWidth
173вҶ’      const h = container.clientHeight
174вҶ’      camera.aspect = w / h
175вҶ’      camera.updateProjectionMatrix()
176вҶ’      renderer.setSize(w, h)
177вҶ’    }
178вҶ’    window.addEventListener('resize', onResize)
179вҶ’
180вҶ’    return () => {
181вҶ’      cancelAnimationFrame(animId)
182вҶ’      window.removeEventListener('mousemove', onMouseMove)
183вҶ’      window.removeEventListener('resize', onResize)
184вҶ’      renderer.dispose()
185вҶ’      torusGeo.dispose()
186вҶ’      torusMat.dispose()
187вҶ’      glowMat.dispose()
188вҶ’      particleGeo.dispose()
189вҶ’      particleMat.dispose()
190вҶ’      orbiters.forEach((o) => {
191вҶ’        o.mesh.geometry.dispose()
192вҶ’        o.mesh.material.dispose()
193вҶ’      })
194вҶ’      if (container.contains(renderer.domElement)) {
195вҶ’        container.removeChild(renderer.domElement)
196вҶ’      }
197вҶ’    }
198вҶ’  }, [])
199вҶ’
200вҶ’  return (
201вҶ’    <div
202вҶ’      ref={mountRef}
203вҶ’      style={{
204вҶ’        position: 'absolute',
205вҶ’        inset: 0,
206вҶ’        zIndex: 0,
207вҶ’        pointerEvents: 'none',
208вҶ’        overflow: 'hidden',
209вҶ’      }}
210вҶ’    />
211вҶ’  )
212вҶ’}
